mapper.select:
SELECT WORK_INDCT_NUM, CUST_NUM, EQUT_CD, PROD_CD, DATE_FORMAT(START_DTTM, '%Y-%m-%d %H:%i:%s') AS START_DTTM, DATE_FORMAT(END_DTTM, '%Y-%m-%d %H:%i:%s') AS END_DTTM FROM tb_jacup WHERE START_DTTM IS NOT NULL AND START_DTTM BETWEEN #{from} AND #{to}
AND EQUT_CD = #{equtCd}
ORDER BY START_DTTM ASC
